class TempDirectory:
    def __init__(self):
        import os
        self.original = os.getcwd()

    def __enter__(self):
        import tempfile
        self.tmpdir = tempfile.mkdtemp()
        import os
        os.chdir(self.tmpdir)
        return self.tmpdir

    def __exit__(self, exc_type, exc_val, exc_tb):
        import os
        import shutil
        os.chdir(self.original)
        shutil.rmtree(self.tmpdir)
        return False

# Separate iterable and iterator (best practice)
class Countdown:
    """Iterable: can be iterated multiple times."""
    def __init__(self, start):
        self.start = start

    def __iter__(self):
        return CountdownIterator(self.start)

class CountdownIterator:
    """Iterator: exhaustible, one-pass."""
    def __init__(self, current):
        self.current = current

    def __iter__(self):
        return self  # iterators return themselves

    def __next__(self):
        if self.current <= 0:
            raise StopIteration
        value = self.current
        self.current -= 1
        return value

