    __slots__ = ('z',)  # only declare NEW slots

    def __init__(self, x, y, z):
        super().__init__(x, y)
        self.z = z

p3 = Point3D(1, 2, 3)
print(p3.x, p3.y, p3.z)  # 1 2 3
print(hasattr(p3, '__dict__'))  # False

# Slots are descriptors on the class
print(type(Point2D.__dict__['x']))  # <class 'member_descriptor'>

# Dunder methods work normally with __slots__
class Vector:
    __slots__ = ('x', 'y')

    def __init__(self, x, y):
        self.x = x
        self.y = y

    def __add__(self, other):
        return Vector(self.x + other.x, self.y + other.y)

    def __repr__(self):
        return f"Vector({self.x}, {self.y})"

    def __eq__(self, other):
        if not isinstance(other, Vector):
            return NotImplemented
        return self.x == other.x and self.y == other.y

    def __hash__(self):
        return hash((self.x, self.y))

v1 = Vector(1, 2)
v2 = Vector(3, 4)
print(v1 + v2)  # Vector(4, 6)
print({v1, v1 + v2})  # {Vector(1, 2), Vector(4, 6)}

class Point:
    __slots__ = ('x', 'y')
    def __init__(self, x, y):
        self.x, self.y = x, y
    def __repr__(self):
        return f"Point({self.x}, {self.y})"

p = Point(1, 2)
print(p)              # Point(1, 2)
# p.z = 3             # AttributeError
print(hasattr(p, '__dict__'))  # False
